To write a first person controller script in GDscript, you can create a class that inherits from the `Node` class. This class will contain methods for controlling the movement of the player character. Here's an example of what the class might look like:
```
class FirstPersonController : Node {
    var move_forward = 0
    var move_backward = 0
    var strafe_left = 0
    var strafe_right = 0

    func update() {
        var velocity = Vector3.zero

        if (move_forward > 0) {
            velocity.x = move_forward
        } else if (move_forward < 0) {
            velocity.x = -move_forward
        }

        if (move_backward > 0) {
            velocity.x = -move_backward
        } else if (move_backward < 0) {
            velocity.x = move_backward
        }

        if (strafe_left > 0) {
            velocity.y = strafe_left
        } else if (strafe_left < 0) {
            velocity.y = -strafe_left
        }

        if (strafe_right > 0) {
            velocity.y = strafe_right
        } else if (strafe_right < 0) {
            velocity.y = -strafe_right
        }

        get_node().set_position(get_node().get_position() + velocity * get_node().get_physics_process_delta_time())
    }
}
```
